import anthropic
import json

client = anthropic.Anthropic()


def run_prompt(system: str, user: str, max_tokens: int = 300) -> str:
    return client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=max_tokens,
        temperature=0.0,
        system=system,
        messages=[{"role": "user", "content": user}],
    ).content[0].text.strip()


EVAL_SET = [
    {
        "question": "How do I cancel my subscription?",
        "gold": "Go to Account Settings → Billing → Cancel Subscription. Changes take effect at end of billing period.",
    },
    {
        "question": "I was charged twice this month.",
        "gold": "Please email billing@example.com with your order IDs and we will refund the duplicate within 3 business days.",
    },
]

