PROMPT_V2 = (
    "You are a friendly customer support agent for a SaaS product. "
    "Answer the customer's question directly and concisely in 2 sentences or fewer. "
    "If you need to direct them to a resource, be specific about where to go."
)


def eval_prompt(system_prompt: str) -> float:
    """Return average overall helpfulness score across the eval set."""
    total = 0.0
    for ex in EVAL_SET:
        answer = run_prompt(system_prompt, ex["question"])
        scores = score_helpfulness(ex["question"], answer, gold_answer=ex["gold"])
        total += scores.get("overall", 0)
    return total / len(EVAL_SET)


